import { EXCLUDED_SECONDARY_ACTIVE_SKILL_IDS } from './excluded-secondary-actives.js';

/**
 * Base URL for the app (e.g. '' for root, '/gem-viability' for GitHub Pages). Used so fetch works when deployed to a subpath.
 */
function getBaseUrl() {
  const base = typeof import.meta !== 'undefined' && import.meta.env?.BASE_URL;
  if (!base || base === '/') return '';
  return base.endsWith('/') ? base.slice(0, -1) : base;
}

/**
 * Load gem data. Expects public/gems.json (generated by scripts/generate-gems-json.js from skill-data/*.lua).
 * Secondary active skills are filtered out so they are not shown or used in compatibility.
 * @returns {Promise<Array<{id: string, name: string, kind: 'active'|'support', primaryStat: string, variant?: string, skillTypes: string[], minionSkillTypes?: string[], requireSkillTypes?: string[], excludeSkillTypes?: string[], requireSkillTypesAlternatives?: string[][], ignoreMinionTypes?: boolean, exceptional?: boolean}>>}
 */
export async function loadGems() {
  const base = getBaseUrl();
  const url = `${base}/gems.json`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to load gem data: ${res.status}`);
  const data = await res.json();
  return data.filter((g) => !EXCLUDED_SECONDARY_ACTIVE_SKILL_IDS.has(g.id));
}
